  const B = Array.from({ length: 12 }, () => Array(4).fill(0));

  A[0][3] = 1;
  A[1][4] = 1;
  A[2][5] = 1;

  A[3][3] = -linearDamping;
  A[4][4] = -linearDamping;
  A[5][5] = -linearDamping;
  A[3][7] = gravity;
  A[4][6] = -gravity;

