  A[7][10] = 1;
  A[8][11] = 1;

  A[9][9] = -angularDamping;
  A[10][10] = -angularDamping;
  A[11][11] = -angularDamping;

  B[5][0] = 1 / mass;
  B[9][1] = 1 / ixx;
  B[10][2] = 1 / iyy;
  B[11][3] = 1 / izz;

