  h[0][0] = 1;
  h[1][1] = 1;
  h[2][2] = 1;
  h[3][6] = 1;
  h[4][7] = 1;
  h[5][8] = 1;
  h[6][9] = 1;
  h[7][10] = 1;
  h[8][11] = 1;
